V = t.TypeVar("V")

if os.name == "nt":
    BEFORE_BAR = "\r"
    AFTER_BAR = "\n"
else:
    BEFORE_BAR = "\r\033[?25l"
    AFTER_BAR = "\033[?25h\n"


class ProgressBar(t.Generic[V]):
    def __init__(
        self,
        iterable: cabc.Iterable[V] | None,
        length: int | None = None,
        fill_char: str = "#",
        empty_char: str = " ",
        bar_template: str = "%(bar)s",
        info_sep: str = "  ",
        hidden: bool = False,
        show_eta: bool = True,
        show_percent: bool | None = None,
        show_pos: bool = False,
        item_show_func: t.Callable[[V | None], str | None] | None = None,
        label: str | None = None,
        file: t.TextIO | None = None,
        color: bool | None = None,
        update_min_steps: int = 1,
        width: int = 30,
    ) -> None:
        """Create a new progress bar.

        Parameters mirror those used by Click's progress bar implementation.
        """
        self.fill_char = fill_char
        self.empty_char = empty_char
        self.bar_template = bar_template
        self.info_sep = info_sep
        self.hidden = hidden
        self.show_eta = show_eta
        self.show_percent = show_percent
        self.show_pos = show_pos
        self.item_show_func = item_show_func
        self.label: str = label or ""

        if file is None:
            file = _default_text_stdout()

            # There are no standard streams attached to write to. For example,
            # pythonw on Windows.
            if file is None:
                file = StringIO()

        self.file = file
        self.color = color
        self.update_min_steps = update_min_steps
        self._completed_intervals = 0
        self.width: int = width
        self.autowidth: bool = width == 0

        if length is None:
            from operator import length_hint

            length = length_hint(iterable, -1)

            if length == -1:
                length = None
        if iterable is None:
            if length is None:
                raise TypeError("iterable or length is required")
            iterable = t.cast("cabc.Iterable[V]", range(length))
        self.iter: cabc.Iterable[V] = iter(iterable)
        self.length = length
        self.pos: int = 0
        self.avg: list[float] = []
        self.last_eta: float
        self.start: float
        self.start = self.last_eta = time.time()
        self.eta_known: bool = False
        self.finished: bool = False
        self.max_width: int | None = None
        self.entered: bool = False
        self.current_item: V | None = None
        self._is_atty = isatty(self.file)
        self._last_line: str | None = None

    def __enter__(self) -> ProgressBar[V]:
        """Enter the context manager for the progress bar.

        This renders the initial progress bar and marks the bar as entered.
        """
        self.entered = True
        self.render_progress()
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        tb: TracebackType | None,
    ) -> None:
        """Exit the context manager and finish rendering the bar."""
        self.render_finish()

    def __iter__(self) -> cabc.Iterator[V]:
        """Return an iterator for the progress bar.

        Iteration is only allowed within the context manager created by
        using the progress bar in a with statement.
        """
        if not self.entered:
            raise RuntimeError("You need to use progress bars in a with block.")
        self.render_progress()
        return self.generator()

    def __next__(self) -> V:
        """Return the next item from the underlying iterator."""
        # Iteration is defined in terms of a generator function,
        # returned by iter(self)
        try:
            return next(self.generator())  # type: ignore[arg-type]
        except StopIteration:
            raise

    def generator(self) -> t.Generator[V, None, None]:
        """Yield items from the underlying iterable while updating the bar."""
        for item in self.iter:
            self.current_item = item
            self.make_step(1)
            yield item
        self.finish()

    def render_finish(self) -> None:
        """Render the final state of the progress bar and clean up the terminal."""
        if self.hidden:
            return
        self.finished = True
        if self._is_atty:
            # Ensure final line is printed and cursor shown again.
            line = self.format_progress_line()
            try:
                self.file.write(BEFORE_BAR + line + AFTER_BAR)
            except OSError:
                # Ignoring write errors on exit.
                pass
        else:
            # When not a TTY, ensure a newline is printed.
            try:
                self.file.write("\n")
            except OSError:
                pass

    def pct(self) -> float | None:
        """Return the fraction completed as a float between 0 and 1."""
        if self.length is None or self.length == 0:
            return None
        return float(self.pos) / float(self.length)

    def time_per_iteration(self) -> float | None:
        """Return the average time per iteration in seconds."""
        if not self.avg:
            return None
        return sum(self.avg) / len(self.avg)

    def eta(self) -> float | None:
        """Return the estimated seconds remaining, or None if unknown."""
        if self.length is None:
            return None
        tpi = self.time_per_iteration()
        if tpi is None:
            return None
        remaining = max(self.length - self.pos, 0)
        return remaining * tpi

    def format_eta(self, seconds: float | None) -> str:
        """Format ETA seconds into a human readable string."""
        if seconds is None:
            return "?:??"
        if seconds >= 3600:
            return "%d:%02d:%02d" % (
                seconds // 3600,
                (seconds % 3600) // 60,
                seconds % 60,
            )
        return "%02d:%02d" % (seconds // 60, seconds % 60)

    def format_pos(self) -> str:
        """Format the current position/length display."""
        if self.length is None:
            return "%d" % (self.pos,)
        return "%d/%d" % (self.pos, self.length)

    def format_pct(self) -> str:
        """Return formatted percentage string."""
        p = self.pct()
        if p is None:
            return ""
        return "%3d%%" % (p * 100)

    def format_bar(self, width: int) -> str:
        """Return the visual bar for a given width."""
        if self.length is None:
            # indeterminate spinner-like behavior: fill proportional to time
            # here we just return a bouncing bar
            filled = int((time.time() - self.start) % (width + 1))
            return self.fill_char * filled + self.empty_char * max(width - filled, 0)
        fraction = 0.0 if self.length == 0 else float(self.pos) / float(self.length)
        filled = int(fraction * width)
        return self.fill_char * filled + self.empty_char * max(width - filled, 0)

    def format_progress_line(self) -> str:
        """Return the complete formatted progress line including label and info."""
        parts: list[str] = []
        if self.label:
            parts.append(self.label)
        if self.autowidth:
            width = self.max_width or self.width or 30
        else:
            width = self.width
        bar = self.format_bar(width)
        parts.append(self.bar_template % {"bar": bar})
        info_parts: list[str] = []
        if self.show_pos:
            info_parts.append(self.format_pos())
        if self.show_percent or (self.show_percent is None and self.length is not None):
            info_parts.append(self.format_pct())
        if self.show_eta:
            eta_str = self.format_eta(self.eta())
            info_parts.append(eta_str)
        info = self.info_sep.join(x for x in info_parts if x)
        if info:
            parts.append(info)
        line = " ".join(parts)
        return line

    def render_progress(self) -> None:
        """Render the progress bar if necessary depending on TTY and state."""
        if self.hidden:
            return
        if not self._is_atty:
            # For non-tty, only write when finished, or not at all.
            return
        line = self.format_progress_line()
        if self._last_line == line:
            return
        try:
            self.file.write(BEFORE_BAR + line)
            self.file.flush()
            self._last_line = line
        except OSError:
            # Ignore write errors during progress display.
            pass

    def make_step(self, step: int = 1) -> None:
        """Advance the progress bar by a given number of steps."""
        now = time.time()
        diff = now - self.last_eta
        if diff > 0:
            self.avg.append(diff)
            if len(self.avg) > 10:
                self.avg.pop(0)
        self.last_eta = now
        self.pos += step
        self.eta_known = self.length is not None and bool(self.avg)
        self._completed_intervals += 1
        if self._completed_intervals >= self.update_min_steps:
            self.render_progress()
            self._completed_intervals = 0

    def finish(self) -> None:
        """Finish the progress bar and render its final state."""
        self.pos = self.length or self.pos
        self.render_finish()


def open_url(url: str, wait: bool = True) -> None:
    """Open the given URL in a web browser, raising ClickException on error.

    This wraps webbrowser.open and raises a ClickException with a helpful
    message if the URL cannot be opened.
    """
    try:
        # webbrowser.open returns True/False on success/failure
        ok = webbrowser.open(url, new=2, autoraise=wait)
    except Exception as exc:
        raise _translate_ch_to_exc(exc, url)
    if not ok:
        raise ClickException(_("Could not open URL: %s") % url)


def _translate_ch_to_exc(exc: BaseException, url: str) -> ClickException:
    """Translate a browser related exception into a ClickException.

    This ensures consistent error messages for failures when launching a browser.
    """
    msg = str(exc)
    if not msg:
        msg = _("Could not open URL: %s") % url
    return ClickException(msg)


class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: t.Mapping[str, str] | None = None,
        require_save: bool = True,
    ) -> None:
        """Create an Editor instance.

        editor: explicit editor command (like "vim" or "notepad")
        env: environment mapping for subprocess
        require_save: when True, raise an error if the file wasn't changed
        """
        self.editor = editor
        self.env = env
        self.require_save = require_save

    def get_editor(self) -> str:
        """Return the editor command to use, either from explicit setting or
        environment variables or sensible defaults."""
        if self.editor:
            return self.editor
        # Check standard environment variables
        for name in ("VISUAL", "EDITOR"):
            val = os.environ.get(name)
            if val:
                return val
        # Fallbacks based on platform
        if WIN:
            return "notepad"
        return os.environ.get("EDITOR", "vi")

    def edit_files(self, filenames: list[str]) -> int:
        """Open the list of filenames in an editor and return the editor process exit code.
        
        This will attempt to honor quoting and environment settings.
        """
        editor_cmd = self.get_editor()
        # If editor has placeholders, replace them
        if "{}" in editor_cmd:
            cmd = editor_cmd.format(" ".join(shlex.quote(f) for f in filenames))
            args = shlex.split(cmd)
        else:
            args = shlex.split(editor_cmd) + filenames
        try:
            # Use os.spawn* or subprocess for simplicity
            import subprocess

            proc = subprocess.Popen(args, env=self.env)
            proc.wait()
            return proc.returncode or 0
        except OSError as exc:
            raise ClickException(_("Could not open editor: %s") % exc)

    def edit(
        self,
        filename: str | None = None,
        text: str | None = None,
        extension: str | None = None,
    ) -> str | None:
        """Open an editor for a single file. If filename is None, a temporary
        file will be used and its contents returned. If text is provided, it
        will be the initial contents of the file."""
        from tempfile import NamedTemporaryFile

        if filename is None:
            suffix = "." + extension if extension else ""
            with NamedTemporaryFile(suffix=suffix, delete=False, mode="w", encoding="utf-8") as tmp:
                if text:
                    tmp.write(text)
                tmp.flush()
                tmp_name = tmp.name
            try:
                rc = self.edit_files([tmp_name])
                if rc != 0:
                    raise ClickException(_("Editor exited with code %d") % rc)
                with open(tmp_name, "r", encoding="utf-8") as f:
                    data = f.read()
                if self.require_save and text is not None and data == text:
                    return None
                return data
            finally:
                try:
                    os.unlink(tmp_name)
                except OSError:
                    pass
        else:
            # edit an existing filename
            if text is not None:
                with open(filename, "w", encoding="utf-8") as f:
                    f.write(text)
            rc = self.edit_files([filename])
            if rc != 0:
                raise ClickException(_("Editor exited with code %d") % rc)
            # If editing in place, nothing to return.
            return None


def _unquote_file(s: str) -> str:
    """Unquote a filename if it is quoted. This is used for editors that
    return filenames wrapped in quotes."""
    if len(s) >= 2 and ((s[0] == s[-1]) and s[0] in ("'", '"')):
        return s[1:-1]
    return s


@contextlib.contextmanager
def raw_terminal(stream):
    """Context manager that places the terminal into raw mode on POSIX.

    On Windows this is a no-op since raw mode is handled differently.
    The stream is expected to be an object with fileno() on POSIX.
    """
    if WIN:
        # On Windows, there is no termios support here; just yield.
        yield
        return
    import termios
    import tty

    fd = stream.fileno()
    old = termios.tcgetattr(fd)
    try:
        tty.setraw(fd)
        yield
    finally:
        try:
            termios.tcsetattr(fd, termios.TCSADRAIN, old)
        except Exception:
            # Best effort to restore terminal
            pass


def getchar(echo: bool = True) -> str:
    """Read a single character from stdin without requiring Enter.

    When echo is False the character will not be printed to the terminal.
    """
    if WIN:
        import msvcrt

        ch = msvcrt.getwch()
        if not echo:
            return ch
        # echo is automatically handled by getwch; return the character
        return ch
    # POSIX implementation
    fd = sys.stdin.fileno()
    with raw_terminal(sys.stdin):
        try:
            ch = os.read(fd, 1)
            if not ch:
                return ""
            c = ch.decode(get_best_encoding() or "utf-8", errors="ignore")
            if echo:
                try:
                    sys.stdout.write(c)
                    sys.stdout.flush()
                except Exception:
                    pass
            return c
        except OSError:
            return ""


# Some environments define different behavior (e.g., Cygwin), provide
# convenience wrappers consistent with Click's API.

@contextlib.contextmanager
def raw_terminal_for_stream(stream):
    """Alternate raw_terminal wrapper maintained for API compatibility."""
    yield from raw_terminal(stream)


def getchar_encoded(echo: bool = True) -> str:
    """Compatibility wrapper for reading a character with encoding awareness."""
    return getchar(echo=echo)